#!/usr/bin/env python3\n\"\"\"\n06_fit_timing.py — Fit polariton centroid to timing model.\n\nSub-Experiment A (Timing sweep):\n    Model: x̄_pol(Δτ) = A · cos(ω · Δτ + φ₀) · exp(−Δτ / τ_decay) + x̄₀\n\nReads aggregated centroid_x_mean_um values across multiple positions/runs\nat different Δτ values, fits the model, and outputs results to JSON.\n\nUsage:\n    python scripts/06_fit_timing.py --input aggregated_timing_data.csv \\\\\n                                    --output fit_timing_results.json\n\"\"\"\n\nimport argparse\nimport json\nimport logging\nfrom pathlib import Path\n\nimport numpy as np\nfrom scipy.optimize import curve_fit\n\nlogger = logging.getLogger(__name__)\nlogging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')\n\n\ndef timing_model(delta_tau, A, omega, tau_decay, x0, phi0):\n    \"\"\"\n    Oscillatory decay model for timing sweep.\n    \n    Parameters:\n        delta_tau: inter-pulse delay (ps)\n        A: oscillation amplitude (µm)\n        omega: angular frequency (rad/ps)\n        tau_decay: exponential decay time constant (ps)\n        x0: DC offset (µm)\n        phi0: initial phase (rad)\n    \n    Returns:\n        x̄_pol: polariton centroid position (µm)\n    \"\"\"\n    return A * np.cos(omega * delta_tau + phi0) * np.exp(-delta_tau / tau_decay) + x0\n\n\ndef bootstrap_ci(data, statistic_func, n_resamples=10000, ci=95):\n    \"\"\"\n    Compute bootstrap confidence interval for a statistic.\n    \n    Args:\n        data: 1D array of data points\n        statistic_func: function that computes the statistic from data\n        n_resamples: number of bootstrap resamples\n        ci: confidence interval percentage (default 95)\n    \n    Returns:\n        (estimate, ci_lower, ci_upper)\n    \"\"\"\n    n = len(data)\n    bootstrap_replicates = []\n    \n    for _ in range(n_resamples):\n        resample = np.random.choice(data, size=n, replace=True)\n        bootstrap_replicates.append(statistic_func(resample))\n    \n    bootstrap_replicates = np.array(bootstrap_replicates)\n    \n    alpha = (100 - ci) / 2\n    ci_lower = np.percentile(bootstrap_replicates, alpha)\n    ci_upper = np.percentile(bootstrap_replicates, 100 - alpha)\n    estimate = statistic_func(data)\n    \n    return estimate, ci_lower, ci_upper\n\n\ndef fit_timing_sweep(delta_tau_array, centroid_array, centroid_std_array=None):\n    \"\"\"\n    Fit the timing model to centroid data.\n    \n    Args:\n        delta_tau_array: array of delays (ps)\n        centroid_array: array of centroid positions (µm)\n        centroid_std_array: optional array of centroid standard deviations (µm)\n    \n    Returns:\n        Dictionary with fit results, parameters, CI, and diagnostics.\n    \"\"\"\n    # Sort by delay for plotting\n    sort_idx = np.argsort(delta_tau_array)\n    delta_tau = delta_tau_array[sort_idx]\n    centroid = centroid_array[sort_idx]\n    \n    if centroid_std_array is not None:\n        centroid_std = centroid_std_array[sort_idx]\n        sigma = centroid_std\n    else:\n        sigma = None\n    \n    # Initial guess\n    p0 = [\n        np.ptp(centroid) / 2,  # A ~ half the range\n        2 * np.pi / (delta_tau[-1] - delta_tau[0]),  # omega ~ 1 oscillation\n        5.0,  # tau_decay ~ 5 ps\n        np.mean(centroid),  # x0 ~ mean\n        0.0,  # phi0 ~ 0\n    ]\n    \n    try:\n        popt, pcov = curve_fit(\n            timing_model,\n            delta_tau,\n            centroid,\n            p0=p0,\n            sigma=sigma,\n            absolute_sigma=True if sigma is not None else False,\n            maxfev=5000,\n        )\n    except RuntimeError as e:\n        logger.error(f\"Curve fit failed: {e}\")\n        return {'error': str(e)}\n    \n    # Extract parameters\n    A, omega, tau_decay, x0, phi0 = popt\n    perr = np.sqrt(np.diag(pcov))\n    \n    # Compute R-squared\n    yhat = timing_model(delta_tau, *popt)\n    ss_res = np.sum((centroid - yhat) ** 2)\n    ss_tot = np.sum((centroid - np.mean(centroid)) ** 2)\n    r_squared = 1 - (ss_res / ss_tot)\n    \n    # Build results dictionary\n    results = {\n        'model': 'A * cos(ω * Δτ + φ₀) * exp(−Δτ / τ_decay) + x₀',\n        'parameters': {\n            'A_um': float(A),\n            'A_um_ci_95': [float(A - 1.96 * perr[0]), float(A + 1.96 * perr[0])],\n            'omega_rad_per_ps': float(omega),\n            'omega_rad_per_ps_ci_95': [float(omega - 1.96 * perr[1]), float(omega + 1.96 * perr[1])],\n            'tau_decay_ps': float(tau_decay),\n            'tau_decay_ps_ci_95': [float(tau_decay - 1.96 * perr[2]), float(tau_decay + 1.96 * perr[2])],\n            'x0_um': float(x0),\n            'x0_um_ci_95': [float(x0 - 1.96 * perr[3]), float(x0 + 1.96 * perr[3])],\n            'phi0_rad': float(phi0),\n            'phi0_rad_ci_95': [float(phi0 - 1.96 * perr[4]), float(phi0 + 1.96 * perr[4])],\n        },\n        'diagnostics': {\n            'r_squared': float(r_squared),\n            'n_points': len(delta_tau),\n            'residual_sum_of_squares': float(ss_res),\n        },\n        'data': {\n            'delta_tau_ps': delta_tau.tolist(),\n            'centroid_um': centroid.tolist(),\n            'centroid_std_um': (centroid_std.tolist() if centroid_std is not None else None),\n        },\n    }\n    \n    logger.info(f\"Fit complete:\")\n    logger.info(f\"  A = {A:.3f} ± {perr[0]:.3f} µm\")\n    logger.info(f\"  ω = {omega:.3f} ± {perr[1]:.3f} rad/ps\")\n    logger.info(f\"  τ_decay = {tau_decay:.3f} ± {perr[2]:.3f} ps\")\n    logger.info(f\"  x₀ = {x0:.3f} ± {perr[3]:.3f} µm\")\n    logger.info(f\"  R² = {r_squared:.4f}\")\n    \n    return results\n\n\nif __name__ == '__main__':\n    parser = argparse.ArgumentParser(\n        description=\"Fit timing model to Sub-Experiment A data.\"\n    )\n    parser.add_argument(\n        '--input',\n        required=True,\n        help='Path to aggregated timing data (CSV with columns: delta_tau_ps, centroid_um, centroid_std_um)'\n    )\n    parser.add_argument(\n        '--output',\n        required=True,\n        help='Path to write fit results (JSON)'\n    )\n    \n    args = parser.parse_args()\n    \n    # Load data\n    input_path = Path(args.input)\n    if not input_path.exists():\n        logger.error(f\"Input file not found: {input_path}\")\n        exit(1)\n    \n    data = np.genfromtxt(input_path, delimiter=',', skip_header=1, names=True)\n    \n    # Fit\n    results = fit_timing_sweep(\n        data['delta_tau_ps'],\n        data['centroid_um'],\n        data['centroid_std_um'] if 'centroid_std_um' in data.dtype.names else None,\n    )\n    \n    # Write output\n    output_path = Path(args.output)\n    with open(output_path, 'w') as f:\n        json.dump(results, f, indent=2)\n    \n    logger.info(f\"Results written to {output_path}\")\n